head.script:
// 물류/작업실적/주유관리/중기별 작업실적 및 주유량 조회

scwin.dateStr = $c.date.getServerDateTime("yyyyMMdd");
scwin.memJson = $c.data.getMemInfo();

scwin.hd_eqCd = ""; // (ASIS)hidden 컴포넌트 > (TOBE)전역변수



//-------------------------------------------------------------------------
// 화면로딩시
//------------------------------------------------------------------------
scwin.onpageload = async function () {
    let e = await $c.sbm.execute(sbm_lobran);
    if (e.responseJSON.GAUCE.length > 0) {
        // asis에 있어서 추가함
        ds_lobran.setRowJSON(ds_lobran.getTotalRow(), {"lobranCd": "ZZZ", "lobranNm": "미사용점소"});
    }

    await scwin.f_getOilStatNm();

    ds_QueryCondition.set("fromWrkDt", scwin.dateStr.substring(0, 4) + scwin.dateStr.substring(4, 6) + "01");
    ds_QueryCondition.set("toWrkDt", scwin.dateStr);

    const param= [
        {
            method: "getLuxeComboDataNoSort",
            param1: "PsCommonEBC",
            param2: "retriveClntCdY",
            compID: "acb_oilStatCd"
        }
    ];
    $c.data.setGauceUtil(param, function() {
        scwin.onLoad = true;
    });
};

scwin.onUdcCompleted = async function() {
    while (!scwin.onLoad) {
        await new Promise(resolve => setTimeout(resolve, 50));
    }
    lc_assgnLobranCd.setValue(scwin.memJson.loUpperLobranCd);
    acb_oilStatCd.setSelectedIndex(39); // <param name=Index value=39>
};


//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search);

    ds_QueryCondition.set("fromWrkDt", scwin.dateStr.substring(0, 4) + scwin.dateStr.substring(4, 6) + "01");
    ds_QueryCondition.set("toWrkDt", scwin.dateStr);

    lc_assgnLobranCd.focus();
};



//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};


scwin.f_openCommonPopUp = async function (disGubun, pWinCloseTF) {
    // 선언부
    var sWinCloseTF = (pWinCloseTF == null) ? "T" : pWinCloseTF;
    var rtnList = new Array();  // 공통POP-UP -> 요청화면 
    var pSelectID = "";
    var pCode = "";
    var pName = "";
    var pWtitleSearch = "";
    var arrParam = new Array();
    var pLobranCd = "";
    var pLobranNm = "";

    pLobranCd = lc_assgnLobranCd.getValue(); //점소코드 

    switch (disGubun) {
        case 1:
            scwin.openPopup = false;
            // 중기 팝업	
            pCode = ed_eqCd.getValue().replace(/\s*$/, '');	// 중기코드
            pName = ed_eqNm.getValue();						// 중기명
            pDate = ed_serFromDate.getValue();		    	// 작업일자

            arrParam[0] = pLobranCd;    				//assgnLobranCd점소코드
            arrParam[1] = ""; 					//eqKndCd중기종류
            arrParam[2] = "";					//clntCd거래처코드
            arrParam[3] = pDate;   				//usblDt작업계획일자
            arrParam[4] = pCode;		  		//eqNo
            arrParam[5] = pName;					//eqNm 중기명 파라미터 넘어가도록 개선 (26.04.23)
            arrParam[6] = sWinCloseTF;	//T,F구분
            arrParam[7] = 'T';	//T,F구분

            var opts = {
                id: "smpPop"
                , popupName: "중기조회"
                , modal: true
                , type: "browserPopup"
                , width: 1000
                , height: 600
            };
            rtnList = await $c.win.openPopup("/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.xml", opts, arrParam);

            if (rtnList != null && rtnList[0] != "N/A" && rtnList[0] != "undefind" && rtnList.length > 0) {

                scwin.hd_eqCd = rtnList[12];	//중기코드
                ed_eqCd.setValue(rtnList[0]);		//중기단축코드

                if (rtnList[1] == "undefind" || rtnList[1].trim() == null || rtnList[1].trim() == "") {
                    ed_eqNm.setValue(rtnList[2]);	//중기명
                } else {
                    ed_eqNm.setValue(rtnList[1]);	//중기번호
                }
            } else {
                scwin.hd_eqCd = "";	//중기코드
                ed_eqCd.setValue("");	//중기단축코드
                ed_eqNm.setValue("");	//중기명					
            }
            break;
    }
};



//-------------------------------------------------------------------------
// TEXT BOX 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopupText = function (inObj, codeObj, disGubun) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우
    if (inObj.getValue().trim() == "" /*|| inObj.readOnly*/) {
        return;
    }

    /*
    if (codeObj.tagName == "OBJECT") {
        codeObj.Text = "";
    } else {
        codeObj.value = "";
    }
    */

    scwin.f_openCommonPopUp(disGubun);
};


//-------------------------------------------------------------------------
// EMEDIT 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopupEmedit = function (inObj, chkObj, txtObj, disGubun) {
    var objValue = inObj.getValue().replace(/^\s*/, '');

    // if (txtObj != null) {
    //     txtObj.setValue("");
    // }

    if (txtObj == "" || txtObj == null) {
        txtObj.setValue("");
        if (chkObj != null) {
            chkObj = "";
            return;
        }
    }

    // 값이 입력이 안된 경우  팝업을 실행하지 않음.
    if (objValue == "" || objValue == null) {
        inObj.setValue("");
        if (chkObj != null) {
            chkObj = "";
            return;
        }
    }

    // 해당 EMEDIT가 Disable 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (/*inObj.ReadOnly || !inObj.Enable ||*/ (chkObj != null && objValue == chkObj)) {
        return;
    }

    scwin.f_openCommonPopUp(disGubun);
};



//-------------------------------------------------------------------------
// 중기 투입실적 및 주유소모량 
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (!await $c.gus.cfValidate([ed_serFromDate, ed_serToDate])) {	// 필수조건 : 중기코드, 작업일자
        return;
    }

    if (!$c.gus.cfIsAfterDate(ed_serFromDate.getValue(), ed_serToDate.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_srchFromDate.focus(); // ASIS 코드 그대로인데 ed_serFromDate 오탈자로 추정됨
        return;
    }


    ds_QueryCondition.set("lobranCd", lc_assgnLobranCd.getValue()); //물류점소코드
    ds_QueryCondition.set("fromWrkDt", ed_serFromDate.getValue()); //조회시작일자
    ds_QueryCondition.set("toWrkDt", ed_serToDate.getValue()); //조회종료일자
    ds_QueryCondition.set("vehclShortCd", ed_eqCd.getValue()); //장비번호
    ds_QueryCondition.set("eqCd", scwin.hd_eqCd); //EQ_CD
    ds_QueryCondition.set("posnClsCd", lc_posnClsCd.getValue()); //소유구분
    ds_QueryCondition.set("oilStatCd", acb_oilStatCd.getValue()); //소유구분

    $c.sbm.execute(sbm_RetrieveWorkResult);

    // gr_RetrieveWorkResult.ColumnProp('eqKndNm', 'SubSumText')='소계';  ??
    ds_RetrieveSubWorkResult.setColumnDefaultValue("eqKndNm", "소계");
};



// 차량별 주유량 등록  
scwin.f_saveOiling = async function () {
    var stdYm = "";
    var oilStatClntNo = "";
    var oilStatClntNm = "";

    scwin.f_retrieveSave();

    for (i = 0; i < ds_RetrieveSubWorkResult.getTotalRow(); i++) {
        if (!$c.gus.cfIsNull(ds_RetrieveSubWorkResult.getCellData(i, "clntNm")) && oilStatClntNm != ds_RetrieveSubWorkResult.getCellData(i, "clntNm")) {
            var wrkYm = ds_RetrieveSubWorkResult.getCellData(i, "wrkDt").substring(0, 6);
            oilStatClntNo = ds_RetrieveSubWorkResult.getCellData(i, "clntNo");
            oilStatClntNm = ds_RetrieveSubWorkResult.getCellData(i, "clntNm");

            var JobYn = await udc_closeYn.cfJobCloseYN("CUR", wrkYm, "00", "TR25", oilStatClntNo, null, "N");	// 집계생성 마감체크(월,재고집계,거래처)			

            if (JobYn == "0" || JobYn == "2") {
                await $c.gus.cfAlertMsg(oilStatClntNm + " 주유소는 해당월 마감처리 되었습니다. \n저장할 수 없습니다.");
                return;
            }
        }
    }

    if (await $c.win.confirm("주유량  마감을 하시겠습니까?")) {
        $c.sbm.execute(sbm_save);
    }
};



scwin.f_retrieveSave = function () {
    var t = 0;
    var row = 0;        // ASIS: var row = 1;
    var totCnt = ds_RetrieveWorkResult.getTotalRow();

    for (var a = 0; a < totCnt; a++) {
        if (ds_RetrieveWorkResult.getCellData(a, "clntNo").trim() == lc_oilStatClntNo.getValue()) {
            ds_RetrieveSubWorkResult.insertRow(row);    // ds_RetrieveSubWorkResult.AddRow();
            ds_RetrieveSubWorkResult.setCellData(row, "lobranNm", ds_RetrieveWorkResult.getCellData(a, "lobranNm"));
            ds_RetrieveSubWorkResult.setCellData(row, "wrkDt", ds_RetrieveWorkResult.getCellData(a, "wrkDt"));
            ds_RetrieveSubWorkResult.setCellData(row, "eqCd", ds_RetrieveWorkResult.getCellData(a, "eqCd"));
            ds_RetrieveSubWorkResult.setCellData(row, "vehclShortCd", ds_RetrieveWorkResult.getCellData(a, "vehclShortCd"));
            ds_RetrieveSubWorkResult.setCellData(row, "vehclNo", ds_RetrieveWorkResult.getCellData(a, "vehclNo"));
            ds_RetrieveSubWorkResult.setCellData(row, "eqKndNm", ds_RetrieveWorkResult.getCellData(a, "eqKndNm"));
            ds_RetrieveSubWorkResult.setCellData(row, "eqNrmNm", ds_RetrieveWorkResult.getCellData(a, "eqNrmNm"));
            ds_RetrieveSubWorkResult.setCellData(row, "wrkStHh", ds_RetrieveWorkResult.getCellData(a, "wrkStHh"));
            ds_RetrieveSubWorkResult.setCellData(row, "wrkEndHh", ds_RetrieveWorkResult.getCellData(a, "wrkEndHh"));
            ds_RetrieveSubWorkResult.setCellData(row, "netOprtHhMintCnt", ds_RetrieveWorkResult.getCellData(a, "netOprtHhMintCnt"));
            ds_RetrieveSubWorkResult.setCellData(row, "clntNo", ds_RetrieveWorkResult.getCellData(a, "clntNo"));
            ds_RetrieveSubWorkResult.setCellData(row, "clntNm", ds_RetrieveWorkResult.getCellData(a, "clntNm"));
            ds_RetrieveSubWorkResult.setCellData(row, "oilingVol", ds_RetrieveWorkResult.getCellData(a, "oilingVol"));
            ds_RetrieveSubWorkResult.setCellData(row, "unitAttritionRate", ds_RetrieveWorkResult.getCellData(a, "unitAttritionRate"));
            ds_RetrieveSubWorkResult.setCellData(row, "drvStaffNo1", ds_RetrieveWorkResult.getCellData(a, "drvStaffNo1"));
            ds_RetrieveSubWorkResult.setCellData(row, "drvStaffNm1", ds_RetrieveWorkResult.getCellData(a, "drvStaffNm1"));
            ds_RetrieveSubWorkResult.setCellData(row, "cvsslNmWrkPlNm", ds_RetrieveWorkResult.getCellData(a, "cvsslNmWrkPlNm"));
            ds_RetrieveSubWorkResult.setCellData(row, "acctDeptCd", ds_RetrieveWorkResult.getCellData(a, "acctDeptCd"));
            ds_RetrieveSubWorkResult.setCellData(row, "lastMonthUnitAttritionRate", ds_RetrieveWorkResult.getCellData(a, "lastMonthUnitAttritionRate"));
            ds_RetrieveSubWorkResult.setCellData(row, "diffRate", ds_RetrieveWorkResult.getCellData(a, "diffRate"));
            row++;
        }
    }
};



scwin.f_oilState = function () {
    co_ds_combo2.removeAll();

    var t = 0;
    var row = 0;        // ASIS: var row = 1;

    for (var a = 0; a < ds_RetrieveWorkResult.getTotalRow(); a++) {

        if (ds_RetrieveWorkResult.getCellData(a, "clntNm").trim() != "") {
            for (var i = 0; i < co_ds_combo2.getTotalRow(); i++) {
                if (ds_RetrieveWorkResult.getCellData(a, "clntNm") == co_ds_combo2.getCellData(i, "name")) {
                    t = 1;
                }
            }

            if (t == 0) {
                co_ds_combo2.insertRow(row);
                co_ds_combo2.setCellData(row, "code", ds_RetrieveWorkResult.getCellData(a, "clntNo"));
                co_ds_combo2.setCellData(row, "name", ds_RetrieveWorkResult.getCellData(a, "clntNm"));
                row++;
            }

            t = 0;
        }
    }

    lc_oilStatClntNo.index = 0;
};



scwin.f_getOilStatNm = async function() { 
    // $c.sbm.execute(sbm_co_ds_combo2);
    let e = await $c.sbm.execute(sbm_co_ds_combo2);
    if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
        co_ds_combo2.setRowJSON(0, {"code":"","name":"전체"}, false);
    }
};



//-------------------------------------------------------------------------
// List 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_toExcel = async function () {
    //sheet명                     , 저장파일명                           , 저장 다이얼로그
    // cfGridToExcel(gr_RetrieveWorkResult , "중기별 주유소모율 작업실적" , "중기별 주유소모율 작업실적.xls" , 4+8+16);
    var fileName = "중기별 주유소모율 작업실적";
    await $c.data.downloadGridViewExcel(gr_RetrieveWorkResult, { fileName: fileName + ".xlsx", sheetName: fileName });
};



// <!-- 조회 DataSet --> 
scwin.sbm_RetrieveWorkResult_submitdone = async function (e) {
    scwin.f_oilState();

    //OnLoadCompleted(rowCnt) event
    // cfHideDSWaitMsg(gr_RetrieveWorkResult);

    if (ds_RetrieveWorkResult.getTotalRow() == 0) {
        await $c.gus.cfAlertMsg("[중기별  작업실적 및 주유소모량  정보] " + MSG_CM_ERR_003);
        await scwin.f_getOilStatNm(); 
    }

    $c.gus.cfEnableBtnOnly([btn_save]);

    var cnt = ds_RetrieveWorkResult.getTotalRow()
    totalRows.setValue(cnt);
};


scwin.gr_RetrieveWorkResult_oncellclick = function (rowIndex, columnIndex, columnId) {
    if (rowIndex < 0) {
        return;
    }
};


// <!-- 중기코드  EMEdit -->
scwin.udc_eqCd_onblurCodeEvent = function (e) {
    scwin.openPopup = true;
    scwin.f_chkOpenCommonPopupEmedit(ed_eqCd, scwin.hd_eqCd, ed_eqNm, 1);
};

scwin.udc_eqCd_onblurNameEvent = function (e) {
    scwin.openPopup = true;
    scwin.f_chkOpenCommonPopupEmedit(ed_eqNm, scwin.hd_eqCd, ed_eqNm, 1);
};



scwin.sbm_save_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    await scwin.f_Retrieve();
};



scwin.udc_eqCd_onclickEvent = function (e) {
    if (scwin.openPopup) {
        scwin.openPopup = false;
        return;
    }
    scwin.f_openCommonPopUp(1, 'F');
};
